// Script Continued Below

function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'publish_tasks') {
		if (g_scratchpad.currentState != -6) {
			return false;
		}

        if (g_scratchpad.calchaschildren == 0) {
			return true;
		} else {
            confirmPublishDraftTasks();
			return false;
        }
    }
}

// Use this function to show either a widget or UI Page modal
function confirmPublishDraftTasks() {
	var taskNumberShortDescription = g_scratchpad.taskerNumber + ': ' + g_form.getValue('short_description');

    var messageTitle = getMessage('Tasker - Title - Publish Selection for') + taskNumberShortDescription;

    // Use widget for Portal
    if (typeof spModal != 'undefined') {
        spModal.open({
            title: messageTitle,
            backdrop: 'static',
            widget: 'tasker_modal_publish_draft_prompt',
            widgetInput: {
                'taskSysId': g_form.getUniqueValue()
            },
			size: 'lg',
            buttons: [],
            footerStyle: {
                'display': 'none'
            }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
        return false;
    } else if (typeof spModal == 'undefined') {
        // For Platform use UI Page named: delete_task_prompt
        var gm = new GlideModal('x_153465_discovert_publiish_draft_task_prompt');
        gm.setTitle(messageTitle);
        gm.setPreference('sysparm_taskSysId', g_form.getUniqueValue());
		gm.setWidth(900);
        gm.render();
    }
}
